                "text": {
                  "type": "match_only_text"
                }
              },
              "type": "keyword"
            }
          }
        }
      ]
    }
  },
  "priority": 200,
  "data_stream": {
    "hidden": false,
    "allow_custom_routing": false
  }
}
```

